SELECT BIN_TO_UUID(reentries.id) AS reentry_id, BIN_TO_UUID(reentries.user_id) AS user_id, users.student_number AS student_number, user_profiles.username AS username, reentries.reentry_count, reentries.status, reentries.note, reentries.created_at, reentries.updated_at FROM reentries JOIN users ON users.id = reentries.user_id JOIN user_profiles ON user_profiles.user_id = reentries.user_id WHERE reentries.status = 'pending' ORDER BY reentries.created_at ASC;
